import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';

class PaymentProcessor {
  final String apiKey;
  final String apiUrl;

  PaymentProcessor({required this.apiKey, required this.apiUrl});

  Future<void> processPayment(String amount, String currency, String paymentMethod) async {
    final url = Uri.parse('$apiUrl/process');
    final headers = {'Authorization': 'Bearer $apiKey', 'Content-Type': 'application/json'};
    final body = jsonEncode({'amount': amount, 'currency': currency, 'payment_method': paymentMethod});

    try {
      final response = await http.post(url, headers: headers, body: body);
      if (response.statusCode == 200) {
        print('Payment processed successfully');
      } else {
        throw Exception('Failed to process payment');
      }
    } catch (e) {
      print('Error processing payment: $e');
    }
  }

  Future<void> integrateMobileWallet(String mobileNumber, String walletType) async {
    final url = Uri.parse('$apiUrl/wallet');
    final headers = {'Authorization': 'Bearer $apiKey', 'Content-Type': 'application/json'};
    final body = jsonEncode({'mobile_number': mobileNumber, 'wallet_type': walletType});

    try {
      final response = await http.post(url, headers: headers, body: body);
      if (response.statusCode == 200) {
        print('Mobile wallet integrated successfully');
      } else {
        throw Exception('Failed to integrate mobile wallet');
      }
    } catch (e) {
      print('Error integrating mobile wallet: $e');
    }
  }
}

void main() {
  final paymentProcessor = PaymentProcessor(apiKey: 'your_api_key', apiUrl: 'https://api.paymentgateway.com');

  runApp(MaterialApp(
    home: Scaffold(
      appBar: AppBar(title: Text('Payment Processor')),
      body: Center(
        child: ElevatedButton(
          onPressed: () async {
            await paymentProcessor.processPayment('100.00', 'USD', 'credit_card');
            await paymentProcessor.integrateMobileWallet('1234567890', 'apple_pay');
          },
          child: Text('Process Payment and Integrate Wallet'),
        ),
      ),
    ),
  ));
}